const jobId = 'test-job-' + Date.now();
return [{
  json: {
    body: {
      job_id:               jobId,
      manim_video_url:      'https://example.com/test-animation.mp4',
      elevenlabs_audio_url: 'https://example.com/test-audio.mp3',
      heygen_avatar_url:    'https://example.com/test-avatar.mp4',
      youtube_title:        'Test Physics Video - Manual Run',
      youtube_description:  'A test physics video generated manually.',
      youtube_tags:         ['physics', 'test', 'education'],
      youtube_channel_id:   'UCtest',
      callback_url:         'http://localhost:5678/webhook/test-callback'
    }
  }
}];

const raw  = $input.first().json;
const body = (raw.body !== undefined) ? raw.body : raw;

const required = ['job_id','manim_video_url','elevenlabs_audio_url','youtube_title','youtube_description','youtube_tags','youtube_channel_id','callback_url'];
for (const f of required) { if (!body[f]) throw new Error('Stage 3 payload missing: ' + f); }

const jobId = body.job_id;
return [{
  json: {
    job_id:               jobId,
    manim_video_url:      body.manim_video_url,
    elevenlabs_audio_url: body.elevenlabs_audio_url,
    heygen_avatar_url:    body.heygen_avatar_url,
    youtube_title:        body.youtube_title,
    youtube_description:  body.youtube_description,
    youtube_tags:         Array.isArray(body.youtube_tags) ? body.youtube_tags : body.youtube_tags.split(',').map(t => t.trim()),
    youtube_channel_id:   body.youtube_channel_id,
    callback_url:         body.callback_url,
    start_time:           Date.now(),
    anim_path:    `/ffmpeg/input/${jobId}_animation.mp4`,
    audio_path:   `/ffmpeg/input/${jobId}_audio.mp3`,
    avatar_path:  `/ffmpeg/input/${jobId}_avatar.mp4`,
    music_path:   `/ffmpeg/config/background_music.mp3`,
    output_path:  `/ffmpeg/output/${jobId}_final.mp4`,
    output_n8n:   `/data/ffmpeg/output/${jobId}_final.mp4`,
    output_filename: `${jobId}_final.mp4`
  }
}];

const { execSync } = require('child_process');
const data = $input.first().json;

const script =
  'curl -L --retry 5 --retry-delay 10 --retry-max-time 600 --max-time 600 --connect-timeout 30' +
  ' -o "' + data.anim_path + '" "' + data.manim_video_url + '" 2>&1\n' +
  'EXIT=$?\n' +
  'if [ $EXIT -eq 0 ] && [ -s "' + data.anim_path + '" ]; then\n' +
  '  echo "DOWNLOAD_OK:' + data.anim_path + '"\n' +
  'else\n' +
  '  echo "DOWNLOAD_FAIL:animation:exit_$EXIT"\n' +
  'fi';

let stdout = '';
try {
  stdout = execSync('docker exec -i ffmpeg-runner bash', { input: script, encoding: 'utf-8', timeout: 620000 });
} catch (err) {
  stdout = err.stdout || err.message || 'DOWNLOAD_FAIL:animation:exception';
}

return [{ json: { ...data, stdout } }];

const { execSync } = require('child_process');
const data = $input.first().json;

const script =
  'curl -L --retry 5 --retry-delay 10 --retry-max-time 300 --max-time 300 --connect-timeout 30' +
  ' -o "' + data.audio_path + '" "' + data.elevenlabs_audio_url + '" 2>&1\n' +
  'EXIT=$?\n' +
  'if [ $EXIT -eq 0 ] && [ -s "' + data.audio_path + '" ]; then\n' +
  '  echo "DOWNLOAD_OK:' + data.audio_path + '"\n' +
  'else\n' +
  '  echo "DOWNLOAD_FAIL:audio:exit_$EXIT"\n' +
  'fi';

let stdout = '';
try {
  stdout = execSync('docker exec -i ffmpeg-runner bash', { input: script, encoding: 'utf-8', timeout: 320000 });
} catch (err) {
  stdout = err.stdout || err.message || 'DOWNLOAD_FAIL:audio:exception';
}

return [{ json: { ...data, stdout } }];

// ── Verify downloads succeeded (HeyGen disabled) ─────────────
const anim   = $('Download Manim Animation').first().json;
const audio  = $('Download ElevenLabs Audio').first().json;
const data   = $('Extract Stage 3 Payload').first().json;

const failures = [
  (anim.stdout  || '').includes('DOWNLOAD_FAIL') ? ('Animation: ' + (anim.stdout||'').split('\n').filter(l=>l.includes('FAIL'))[0]) : null,
  (audio.stdout || '').includes('DOWNLOAD_FAIL') ? ('Audio: '     + (audio.stdout||'').split('\n').filter(l=>l.includes('FAIL'))[0]) : null
].filter(Boolean);

if (failures.length > 0) {
  throw new Error('Asset download(s) failed:\n' + failures.join('\n'));
}

return [{ json: data }];

const { execSync } = require('child_process');
const data = $input.first().json;

const fc = '[0:v]scale=1920:1080:force_original_aspect_ratio=decrease,pad=1920:1080:(ow-iw)/2:(oh-ih)/2,setsar=1,fps=30[outv];[1:a]volume=1.0[narr];[2:a]volume=0.15,aloop=loop=-1:size=2e+09[bgm];[narr][bgm]amix=inputs=2:duration=first:dropout_transition=2[outa]';

const script =
  'timeout 1800 ffmpeg -y' +
  ' -i "' + data.anim_path + '"' +
  ' -i "' + data.audio_path + '"' +
  ' -i "' + data.music_path + '"' +
  ' -filter_complex "' + fc + '"' +
  ' -map "[outv]" -map "[outa]"' +
  ' -c:v libx264 -preset medium -crf 18' +
  ' -c:a aac -b:a 192k' +
  ' -movflags +faststart -pix_fmt yuv420p -r 30' +
  ' "' + data.output_path + '" 2>&1\n' +
  'EXIT=$?\n' +
  'if [ $EXIT -eq 0 ] && [ -s "' + data.output_path + '" ]; then\n' +
  '  SIZE=$(du -sh "' + data.output_path + '" | cut -f1)\n' +
  '  echo "FFMPEG_SUCCESS:' + data.output_path + ':size_$SIZE"\n' +
  'else\n' +
  '  echo "FFMPEG_FAILED:exit_$EXIT"\n' +
  'fi';

let stdout = '';
try {
  stdout = execSync('docker exec -i ffmpeg-runner bash', { input: script, encoding: 'utf-8', timeout: 1820000 });
} catch (err) {
  stdout = err.stdout || err.message || 'FFMPEG_FAILED:exception';
}

return [{ json: { ...data, stdout } }];

const item   = $input.first().json;
const stdout = (item.stdout || '').trim();
const data   = $('Extract Stage 3 Payload').first().json;

if (stdout.includes('FFMPEG_FAILED')) {
  const tail = stdout.split('\n').slice(-25).join('\n');
  throw new Error('FFmpeg assembly failed.\n\nLast output:\n' + tail);
}
if (!stdout.includes('FFMPEG_SUCCESS')) {
  console.warn('FFMPEG_SUCCESS signal not found. Proceeding cautiously. stdout: ' + stdout.slice(-300));
}

return [{ json: data }];

// ── Verify YouTube upload returned a video ID ─────────────────
const ytItem = $input.first().json;
if (!ytItem.id) {
  throw new Error('YouTube upload did not return a video ID. Response: ' + JSON.stringify(ytItem).slice(0, 300));
}
// Pass through both yt data AND original payload data
const payload = $('Extract Stage 3 Payload').first().json;
return [{ json: { ...payload, yt_video_id: ytItem.id } }];

const driveNode = $('Upload Final Video to Drive').first().json;
const ytVerify  = $('Verify YouTube Upload').first().json;
const payload   = $('Extract Stage 3 Payload').first().json;

const driveFileId    = driveNode.id;
const ytVideoId      = ytVerify.yt_video_id;
const youtubeUrl     = `https://www.youtube.com/watch?v=${ytVideoId}`;
const finalVideoUrl  = `https://drive.google.com/uc?export=download&id=${driveFileId}`;
const totalTimeSec   = Math.round((Date.now() - payload.start_time) / 1000);

return [{
  json: {
    job_id:                payload.job_id,
    callback_url:          payload.callback_url,
    youtube_url:           youtubeUrl,
    youtube_video_id:      ytVideoId,
    final_video_url:       finalVideoUrl,
    drive_file_id:         driveFileId,
    assembly_time_seconds: totalTimeSec
  }
}];
